'use client';

import { useEffect, useState } from 'react';
import { UserCheck, Search, Trash2 } from 'lucide-react';
import { AdminCard, AdminCardContent, AdminCardHeader, AdminCardTitle } from '@/components/admin/ui/AdminCard';
import { AdminButton } from '@/components/admin/ui/AdminButton';
import { DeleteConfirmModal } from '@/components/admin/ui/DeleteConfirmModal';
import adminApiService from '@/services/adminApiService';
import LoadingSpinner from '@/components/admin/ui/LoadingSpinner';

export default function ResidentsPage() {
  const [residents, setResidents] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);

  // Delete Modal State
  const [deleteModalOpen, setDeleteModalOpen] = useState(false);
  const [residentToDelete, setResidentToDelete] = useState<string | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  // Notification State
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  useEffect(() => {
    loadResidents();
  }, [page, search]);

  const loadResidents = async () => {
    try {
      setLoading(true);
      const response = await adminApiService.getResidents({ page, limit: 10, search });
      if (response.data) {
        const data = response.data as any;
        const residentsData = data.residents || data.data || (Array.isArray(data) ? data : []);
        setResidents(Array.isArray(residentsData) ? residentsData : []);
        setTotal(data.pagination?.total || data.total || 0);
      }
    } catch (error) {
      console.error('Erreur:', error);
      setResidents([]);
    } finally {
      setLoading(false);
    }
  };

  const confirmDelete = (id: string) => {
    setResidentToDelete(id);
    setDeleteModalOpen(true);
  };

  const handleDelete = async () => {
    if (!residentToDelete) return;

    try {
      setIsDeleting(true);
      // Wait for backend endpoint if not fully compatible, but using deleteUser as resident is a user
      await adminApiService.deleteUser(residentToDelete);
      setNotification({ message: 'Résident supprimé avec succès.', type: 'success' });
      setDeleteModalOpen(false);
      setResidentToDelete(null);
      loadResidents();
    } catch (error) {
      console.error('Erreur:', error);
      setNotification({ message: 'Erreur lors de la suppression du résident.', type: 'error' });
      setDeleteModalOpen(false);
    } finally {
      setIsDeleting(false);
      setTimeout(() => setNotification(null), 5000);
    }
  };

  if (loading && residents.length === 0) {
    return <LoadingSpinner fullScreen />;
  }

  return (
    <div className="space-y-6 relative">
      {/* Notifications */}
      {notification && (
        <div className={`fixed top-4 right-4 z-50 p-4 rounded-lg shadow-lg flex items-center gap-3 animate-in fade-in slide-in-from-top-4 ${
          notification.type === 'success' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
        }`}>
          <span className="font-semibold">{notification.message}</span>
        </div>
      )}

      {/* Delete Confirmation Modal */}
      <DeleteConfirmModal 
        isOpen={deleteModalOpen}
        onClose={() => !isDeleting && setDeleteModalOpen(false)}
        onConfirm={handleDelete}
        title="Supprimer le résident"
        message="Êtes-vous sûr de vouloir supprimer ce résident ? Cette action supprimera également ses consommations et factures associées."
        isLoading={isDeleting}
      />

      <div>
        <h1 className="text-3xl font-bold text-gray-900">Résidents</h1>
        <p className="text-gray-600 mt-1">Gérez tous les résidents</p>
      </div>

      <AdminCard>
        <AdminCardContent>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
            <input
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Rechercher un résident..."
              className="w-full pl-10 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#FFA800] focus:border-transparent"
            />
          </div>
        </AdminCardContent>
      </AdminCard>

      <AdminCard>
        <AdminCardHeader>
          <AdminCardTitle>{total} résident{total > 1 ? 's' : ''}</AdminCardTitle>
        </AdminCardHeader>
        <AdminCardContent>
          {residents.length === 0 ? (
            <div className="text-center py-12">
              <UserCheck size={48} className="mx-auto text-gray-400 mb-4" />
              <p className="text-gray-600">Aucun résident trouvé</p>
            </div>
          ) : (
            <div className="overflow-x-auto -mx-4 md:mx-0">
              <div className="inline-block min-w-full align-middle">
                <div className="overflow-hidden">
                  <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="px-3 md:px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase tracking-wider whitespace-nowrap">Nom</th>
                        <th className="px-3 md:px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase tracking-wider whitespace-nowrap">Email</th>
                        <th className="px-3 md:px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase tracking-wider whitespace-nowrap">Téléphone</th>
                        <th className="px-3 md:px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase tracking-wider whitespace-nowrap">Maison</th>
                        <th className="px-3 md:px-4 py-3 text-right text-xs font-semibold text-gray-700 uppercase tracking-wider whitespace-nowrap">Actions</th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {residents.map((resident) => (
                        <tr key={resident._id} className="hover:bg-gray-50">
                          <td className="px-3 md:px-4 py-3 whitespace-nowrap text-sm font-semibold text-gray-900">
                            {resident.prenom} {resident.nom}
                          </td>
                          <td className="px-3 md:px-4 py-3 whitespace-nowrap text-sm text-gray-600">{resident.email}</td>
                          <td className="px-3 md:px-4 py-3 whitespace-nowrap text-sm text-gray-600">{resident.telephone}</td>
                          <td className="px-3 md:px-4 py-3 whitespace-nowrap text-sm text-gray-600">
                            {resident.maison?.nomMaison || 'N/A'}
                          </td>
                          <td className="px-3 md:px-4 py-3 whitespace-nowrap text-right text-sm font-medium">
                            <button
                              onClick={() => confirmDelete(resident._id)}
                              className="p-2 text-gray-600 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors text-red-500"
                              title="Supprimer"
                            >
                              <Trash2 size={18} />
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          )}

          {/* Pagination */}
          {total > 10 && (
            <div className="flex items-center justify-between mt-6 pt-6 border-t border-gray-200">
              <p className="text-sm text-gray-600">
                Page {page} sur {Math.ceil(total / 10)}
              </p>
              <div className="flex gap-2">
                <AdminButton
                  variant="outline"
                  size="sm"
                  onClick={() => setPage(p => Math.max(1, p - 1))}
                  disabled={page === 1}
                >
                  Précédent
                </AdminButton>
                <AdminButton
                  variant="outline"
                  size="sm"
                  onClick={() => setPage(p => p + 1)}
                  disabled={page >= Math.ceil(total / 10)}
                >
                  Suivant
                </AdminButton>
              </div>
            </div>
          )}
        </AdminCardContent>
      </AdminCard>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { Settings, Save, AlertCircle, CheckCircle, Activity, Server, Mail, Phone, Globe, FileText } from 'lucide-react';
import { AdminCard, AdminCardContent, AdminCardHeader, AdminCardTitle } from '@/components/admin/ui/AdminCard';
import { AdminButton } from '@/components/admin/ui/AdminButton';
import adminApiService from '@/services/adminApiService';
import LoadingSpinner from '@/components/admin/ui/LoadingSpinner';

interface SystemInfo {
  version?: {
    api: string;
    node: string;
    platform: string;
  };
  uptime?: {
    days: number;
    hours: number;
    minutes: number;
    total: number;
  };
  memory?: {
    used: string;
    total: string;
    percentage: string;
  };
  database?: {
    type: string;
    version: string;
    status: string;
  };
  environment?: string;
  timestamp?: string;
}

interface AppInfoData {
  email: string;
  phone: string;
  website: string;
  description: string;
  guideRapideUrl: string;
  privacyPolicyUrl: string;
}

export default function SettingsPage() {
  const [settings, setSettings] = useState<any>({});
  const [appInfo, setAppInfo] = useState<AppInfoData>({
    email: '',
    phone: '',
    website: '',
    description: '',
    guideRapideUrl: '',
    privacyPolicyUrl: '',
  });
  const [systemInfo, setSystemInfo] = useState<SystemInfo>({});
  const [loading, setLoading] = useState(true);
  const [loadingSystemInfo, setLoadingSystemInfo] = useState(true);
  const [loadingAppInfo, setLoadingAppInfo] = useState(true);
  const [saving, setSaving] = useState(false);
  const [savingAppInfo, setSavingAppInfo] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  useEffect(() => {
    loadSettings();
    loadSystemInfo();
    loadAppInfo();
  }, []);

  const loadAppInfo = async () => {
    setLoadingAppInfo(true);
    try {
      const response = await adminApiService.getAppInfo();
      if (response.data) {
        setAppInfo({
          email: response.data.email || '',
          phone: response.data.phone || '',
          website: response.data.website || '',
          description: response.data.description || '',
          guideRapideUrl: response.data.guideRapideUrl || '',
          privacyPolicyUrl: response.data.privacyPolicyUrl || '',
        });
      }
    } catch (error) {
      console.error('Erreur chargement paramètres contact:', error);
    } finally {
      setLoadingAppInfo(false);
    }
  };

  const handleSaveAppInfo = async () => {
    setSavingAppInfo(true);
    setMessage(null);
    try {
      await adminApiService.updateAppInfo(appInfo);
      setMessage({ type: 'success', text: 'Paramètres de contact enregistrés. Ils seront visibles dans l\'app mobile.' });
      setTimeout(() => setMessage(null), 4000);
    } catch (error: unknown) {
      setMessage({ type: 'error', text: error instanceof Error ? error.message : 'Erreur lors de la sauvegarde' });
    } finally {
      setSavingAppInfo(false);
    }
  };

  const loadSettings = async () => {
    setLoading(true);
    try {
      // Simuler le chargement des paramètres
      await new Promise(resolve => setTimeout(resolve, 1000));
      // Utiliser des valeurs par défaut
      setSettings({
        general: {
          appName: 'Ecopower',
          baseUrl: 'https://ecopower-api.vercel.app',
          apiVersion: '1.0.0'
        },
        security: {
          tokenExpiry: 15,
          passwordMinLength: 8
        }
      });
    } catch (error) {
      console.error('Erreur:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadSystemInfo = async () => {
    try {
      setLoadingSystemInfo(true);
      const response = await adminApiService.getSystemInfo();
      if (response.data) {
        setSystemInfo(response.data as SystemInfo);
      }
    } catch (error) {
      console.error('Erreur lors du chargement des informations système:', error);
    } finally {
      setLoadingSystemInfo(false);
    }
  };

  const formatUptime = (uptime?: { days: number; hours: number; minutes: number }) => {
    if (!uptime) return 'N/A';
    return `${uptime.days}j ${uptime.hours}h ${uptime.minutes}m`;
  };

  const formatMemory = (memory?: { used: string; total: string }) => {
    if (!memory) return 'N/A';
    return `${memory.used} / ${memory.total}`;
  };

  const formatDatabase = (database?: { type: string; version: string }) => {
    if (!database) return 'N/A';
    return `${database.type} ${database.version}`;
  };

  const handleSave = async () => {
    setSaving(true);
    setMessage(null);
    try {
      // Simuler la sauvegarde
      await new Promise(resolve => setTimeout(resolve, 2000));
      setMessage({ type: 'success', text: 'Paramètres sauvegardés avec succès' });
      setTimeout(() => setMessage(null), 3000);
    } catch (error: any) {
      setMessage({ type: 'error', text: error.message || 'Erreur lors de la sauvegarde' });
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return <LoadingSpinner fullScreen />;
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
