  email: string;
  telephone: string;
  role: string;
  createdAt?: string;
  updatedAt?: string;
  statut?: string;
  homeLatitude?: number;
  homeLongitude?: number;
  homeCity?: string;
  homeCountry?: string;
  homeLocationSource?: string;
