    _id?: string;
    nomMaison?: string;
    adresse?: string | {
      rue?: string;
      ville?: string;
      pays?: string;
    };
  };
  maison?: {
    _id?: string;
    nomMaison?: string;
    adresse?: string | {
      rue?: string;
      ville?: string;
      pays?: string;
    };
  };
  abonnementId?: string | {
    _id?: string;
    typeAbonnement?: string;
    statut?: string;
    dateDebut?: string;
    dateFin?: string;
  };
  abonnement?: {
    _id?: string;
    typeAbonnement?: string;
    statut?: string;
    dateDebut?: string;
    dateFin?: string;
  };
  idProprietaire?: string | {
    _id?: string;
    nom?: string;
    prenom?: string;
